import{_ as s,o as a,c as e,e as t}from"./app-27e24db2.js";const p={};function o(l,n){return a(),e("div",null,n[0]||(n[0]=[t(`<h2 id="代理与反射" tabindex="-1"><a class="header-anchor" href="#代理与反射" aria-hidden="true">#</a> 代理与反射</h2><p>ECMAScript 6 新增的代理和反射为开发者提供了拦截并向基本操作嵌入额外行为的能力</p><h3 id="代理基础" tabindex="-1"><a class="header-anchor" href="#代理基础" aria-hidden="true">#</a> 代理基础</h3><p>代理是目标对象的抽象</p><h4 id="创建空代理" tabindex="-1"><a class="header-anchor" href="#创建空代理" aria-hidden="true">#</a> 创建空代理</h4><p>最简单的代理是空代理，即除了作为一个抽象的目标对象，什么也不做</p><p>代理使用 Proxy 构造函数创建，接收两个必填参数：目标对象和处理程序对象</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token string">&#39;target&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> handler <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> handler<span class="token punctuation">)</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>target <span class="token operator">===</span> proxy<span class="token punctuation">)</span> <span class="token comment">// false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>针对上述代码中 <code>target</code> 和 <code>proxy</code> 两个对象，注意：</p><ul><li>hasOwnProperty() 方法都会应用到目标对象</li><li>Proxy.prototype 是 undefined，因此不能使用 instanceof 操作符检查对象是否是代理</li></ul></blockquote><h4 id="定义捕获器" tabindex="-1"><a class="header-anchor" href="#定义捕获器" aria-hidden="true">#</a> 定义捕获器</h4><p>使用代理的主要目的是可以定义<strong>捕获器（trap）</strong></p><p>例如，定义一个 get() 捕获器，在 ECMAScript 操作以某种形式调用 get() 时触发：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> handler <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> <span class="token string">&#39;handler override&#39;</span>
	<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> handler<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>注意：</p><ul><li>get() 不是 ECMAScript 对象可以调用的方法</li><li>proxy[property]、proxy.property 或 Object.create(proxy)[property] 等操作都可以触发基本的 get() 操作以获取属性</li></ul></blockquote><h4 id="捕获器参数和反射-api" tabindex="-1"><a class="header-anchor" href="#捕获器参数和反射-api" aria-hidden="true">#</a> 捕获器参数和反射 API</h4><p>所有捕获器都可以访问相应的参数，基于这些参数可以重建被捕获方法的原始行为</p><p>比如，get() 捕获器接收以下参数：</p><ul><li>目标对象</li><li>要查询的属性</li><li>代理本身</li></ul><p>通过这些参数可以重建被捕获方法的原始行为：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> handler <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token function">get</span><span class="token punctuation">(</span>trapTarget<span class="token punctuation">,</span> property<span class="token punctuation">,</span> receiver<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">return</span> trapTarget<span class="token punctuation">[</span>property<span class="token punctuation">]</span>
	<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> handler<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但并非所有捕获器行为都像 get() 这么简单，因此 ECMAScript 6 为所有捕获器定义了一组默认行为，这些行为可以在 Reflect 对象上找到</p><p>处理程序对象所有可以捕获的方法都有对应的反射（Reflect）API 方法，使用反射 API 定义空代理对象：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> Reflect<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在反射 API 的基础上可以用最少的代码修改捕获的方法。比如，在某个属性被访问时，对返回的值进行一番修饰：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> handler <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token function">get</span><span class="token punctuation">(</span>trapTarget<span class="token punctuation">,</span> property<span class="token punctuation">,</span> receiver<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token keyword">const</span> decoration <span class="token operator">=</span> property <span class="token operator">===</span> <span class="token string">&#39;foo&#39;</span> <span class="token operator">?</span> <span class="token string">&#39;!!!&#39;</span> <span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
		<span class="token keyword">return</span> Reflect<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token operator">...</span>arguments<span class="token punctuation">)</span> <span class="token operator">+</span> decoration
	<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> handler<span class="token punctuation">)</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>proxy<span class="token punctuation">.</span>foo<span class="token punctuation">)</span> <span class="token comment">// bar!!!</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="捕获器不变式" tabindex="-1"><a class="header-anchor" href="#捕获器不变式" aria-hidden="true">#</a> 捕获器不变式</h4><p>捕获器处理程序的行为必须遵守“捕获器不变式（trap invariant）”</p><p>比如，如果目标对象有一个不可配置且不可写的数据属性，那么在捕获器返回一个与该属性不同的值时，会抛出 TypeError</p><h4 id="可撤销代理" tabindex="-1"><a class="header-anchor" href="#可撤销代理" aria-hidden="true">#</a> 可撤销代理</h4><p>new Proxy() 创建的代理对象与目标对象之间的联系会在代理对象的生命周期内一直存在</p><p>Proxy.revocable() 方法创建一个可撤销的代理，返回一个对象，包含两个属性：</p><ul><li>proxy：新创建的代理对象</li><li>revoke：一个函数，调用后会撤销代理</li></ul><blockquote><p>注意：</p><ul><li>撤销代理的操作时不可逆的</li><li>撤销函数（revoke()）是幂等的，调用多少次结果都一样</li><li>撤销代理之后再调用代理会抛出 TypeError</li></ul></blockquote><h4 id="实用反射-api" tabindex="-1"><a class="header-anchor" href="#实用反射-api" aria-hidden="true">#</a> 实用反射 API</h4><p>某些情况下应该优先使用反射 API：</p><p><strong>1. 反射 API 与 对象 API</strong></p><ul><li>反射 API 并不限于捕获处理程序</li><li>大多数反射 API 方法在 Object 类型上有对应的方法</li><li>Object 上的方法适用于通用程序，而反射方法适用于细粒度的对象控制与操作</li></ul><p><strong>2. 状态标记</strong></p><p>很多反射方法返回称作“状态标记”的布尔值，表示操作是否成功。</p><p>以下方法都会提供状态标记：</p><ul><li>Reflect.defineProperty()</li><li>Reflect.preventExtensions()</li><li>Reflect.setPrototypeOf()</li><li>Reflect.set()</li><li>Reflect.deleteProperty()</li></ul><p><strong>3. 用一等函数替代操作符</strong></p><ul><li>Reflect.get()，替代对象属性访问操作符</li><li>Reflect.set()，替代=赋值操作符</li><li>Reflect.has()，替代 in 操作符或 with()</li><li>Reflect.deleteProperty()，替代 delete 操作符</li><li>Reflect.construct()，替代 new 操作符</li></ul><p><strong>4. 安全地应用函数</strong></p><p>在通过 apply 方法调用函数，被调用的函数可能也定义了自己的 apply 属性，此时：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token class-name">Function</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>myFunc<span class="token punctuation">,</span> thisVal<span class="token punctuation">,</span> argumentList<span class="token punctuation">)</span>

<span class="token comment">// 可替换为</span>
<span class="token function">Reflect</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>myFunc<span class="token punctuation">,</span> thisVal<span class="token punctuation">,</span> argumentList<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="代理另外一个代理" tabindex="-1"><a class="header-anchor" href="#代理另外一个代理" aria-hidden="true">#</a> 代理另外一个代理</h4><p>代理可以拦截反射 API 的操作，而这意味着完全可以创建一个代理，通过它去代理另外一个代理。这样就可以在一个目标对象上建立多层拦截网：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token punctuation">{</span>
	<span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> firstProxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> <span class="token punctuation">{</span>
	<span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;first proxy&#39;</span><span class="token punctuation">)</span>
		<span class="token keyword">return</span> Reflect<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token operator">...</span>arguments<span class="token punctuation">)</span>
	<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> secondProxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>firstProxy<span class="token punctuation">,</span> <span class="token punctuation">{</span>
	<span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;second proxy&#39;</span><span class="token punctuation">)</span>
		<span class="token keyword">return</span> Reflect<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token operator">...</span>arguments<span class="token punctuation">)</span>
	<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>secondProxy<span class="token punctuation">.</span>foo<span class="token punctuation">)</span>
<span class="token comment">// second proxy</span>
<span class="token comment">// first proxy</span>
<span class="token comment">// bar</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="代理的问题与不足" tabindex="-1"><a class="header-anchor" href="#代理的问题与不足" aria-hidden="true">#</a> 代理的问题与不足</h4><p><strong>1. 代理中的 this</strong></p><p>如果目标对象依赖于对象标识，那就可能遇到意料之外的问题</p><p><strong>2. 代理与内部插槽</strong> 有些 ECMAScript 内置类型可能会依赖代理无法控制的机制，结果导致在代理上调用某些方法会出错</p><p>比如，Date 类型方法的执行依赖 this 值上的内部槽位 [[NumberDate]]，代理对象上不存在这个内部槽位，而且这个内部槽位的值也不能通过普通的 get() 和 set() 访问到，于是代理拦截后本应转发给目标对象的方法会抛出 TypeError：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> target <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>proxy <span class="token keyword">instanceof</span> <span class="token class-name">Date</span><span class="token punctuation">)</span> <span class="token comment">// true</span>
proxy<span class="token punctuation">.</span><span class="token function">getDate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// TypeError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="代理捕获器与反射方法" tabindex="-1"><a class="header-anchor" href="#代理捕获器与反射方法" aria-hidden="true">#</a> 代理捕获器与反射方法</h3><p>代理可以捕获 13 种不同的基本操作，这些操作有不同的反射 API 方法、参数、关联 ECMAScript 操作和不变式</p><ul><li>get()</li><li>set()</li><li>has()</li><li>definedProperty()</li><li>getOwnPropertyDescriptor()</li><li>deleteProperty()</li><li>ownKeys()</li><li>getPrototypeOf()</li><li>setPrototypeOf()</li><li>isExtensible()</li><li>preventExtensions()</li><li>apply()</li><li>construct()</li></ul><h3 id="代理模式" tabindex="-1"><a class="header-anchor" href="#代理模式" aria-hidden="true">#</a> 代理模式</h3><p>使用代理可以在代码中实现一些有用的编程模式</p><ul><li>跟踪属性访问</li><li>隐藏属性</li><li>属性验证</li><li>函数与构造函数参数验证</li><li>数据绑定与可观察对象</li></ul>`,61)]))}const i=s(p,[["render",o],["__file","09.html.vue"]]);export{i as default};
